using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
            // Preserve the old name so existing 500K documents remain readable and
            // direct SQL queries that reference c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the default id format from "EntityName|<key>" to just "<key>".
            // Use IdProperty to keep the legacy "Product|<key>" format for compatibility
            // with existing documents.
            entity.Property(p => p.Id).ToJsonProperty("id");
            entity.HasKey(p => p.Id);
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Preserve the EF Core 8 id format: "EntityType|KeyValue"
        configurationBuilder.Conventions.Add(_ =>
            new Microsoft.EntityFrameworkCore.Cosmos.Conventions.IdFormatConvention());
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

